form:Form.form:Scripts:
		function OnLoad()
{                      
	var day=new Date();   
	Ctrl("anno").SetTypedValue(day.getFullYear());

	OnChangeAnno();	
}                                  

function SetData()
{

	var np, nSQL;
	np = new NomadProxy("", ut);
	nSQL = np.SQLService();

	//LICENCIAS 

	var resultlic = nSQL.Get(Ctrl("main").getResource("QRY_LICENCIAS"), "<LEGAJO anno=\"" + Ctrl("anno").GetXValue() + "\" id=\"" + Ctrl("oi_personal_emp").GetXValue() + "\"/>");		
	var xmldoc_lic = new NomadXML(resultlic);	    

	for(var doc = xmldoc_lic.FirstChild();doc != null;doc = doc.Next())	
	{	
		var f_ini = str2date(doc.GetAttr("f_inicio"));
		var f_fin = str2date(doc.GetAttr("f_fin"));		

		for (var cday = f_ini;cday <= f_fin; cday.setDate(cday.getDate()+1))
		{		
			var fecha = date2str(cday);									
			var row = Ctrl("DAYS").AddRow()
			row.SetAttr("id",fecha);
			row.SetAttr("fecha",fecha);
			row.SetAttr("color","FF0000");
		}
	}
	//PROCESOS NO CERRADOS	
	var resultnocer = nSQL.Get(Ctrl("main").getResource("QRY_NOCERRADO"), "<LEGAJO anno=\"" + Ctrl("anno").GetXValue() + "\" id=\"" + Ctrl("oi_personal_emp").GetXValue() + "\"/>");		
	var xmldoc_nocer = new NomadXML(resultnocer);	    

	for(var doc = xmldoc_nocer.FirstChild();doc != null;doc = doc.Next())
	{
		var fecha = doc.GetAttr("fecha");
		var row = Ctrl("DAYS").AddRow()
		row.SetAttr("id",fecha);
		row.SetAttr("fecha",fecha);
		row.SetAttr("color","E0CD00");
	}

	//PROCESOS CERRADOS	
	var resultcer = nSQL.Get(Ctrl("main").getResource("QRY_CERRADO"), "<LEGAJO anno=\"" + Ctrl("anno").GetXValue() + "\" id=\"" + Ctrl("oi_personal_emp").GetXValue() + "\"/>");		
	var xmldoc_cer = new NomadXML(resultcer);	    

	for(var doc = xmldoc_cer.FirstChild();doc != null;doc = doc.Next())
	{
		var fecha = doc.GetAttr("fecha");
		var row = Ctrl("DAYS").AddRow()
		row.SetAttr("id",fecha);
		row.SetAttr("fecha",fecha);
		row.SetAttr("color","FF7700");
	}
}


function OnChangeAnno()
{
	SetData();
	Ctrl("CAL_ENE").SetTypedValue(Ctrl("anno").TypedValue()*100+ 1);	
	Ctrl("CAL_FEB").SetTypedValue(Ctrl("anno").TypedValue()*100+ 2);
	Ctrl("CAL_MAR").SetTypedValue(Ctrl("anno").TypedValue()*100+ 3);
	Ctrl("CAL_ABR").SetTypedValue(Ctrl("anno").TypedValue()*100+ 4);

	Ctrl("CAL_MAY").SetTypedValue(Ctrl("anno").TypedValue()*100+ 5);
	Ctrl("CAL_JUN").SetTypedValue(Ctrl("anno").TypedValue()*100+ 6);
	Ctrl("CAL_JUL").SetTypedValue(Ctrl("anno").TypedValue()*100+ 7);
	Ctrl("CAL_AGO").SetTypedValue(Ctrl("anno").TypedValue()*100+ 8);

	Ctrl("CAL_SEP").SetTypedValue(Ctrl("anno").TypedValue()*100+ 9);
	Ctrl("CAL_OCT").SetTypedValue(Ctrl("anno").TypedValue()*100+10);
	Ctrl("CAL_NOV").SetTypedValue(Ctrl("anno").TypedValue()*100+11);
	Ctrl("CAL_DIC").SetTypedValue(Ctrl("anno").TypedValue()*100+12);	
}

function PrevYear()
{
	Ctrl("anno").SetTypedValue(Ctrl("anno").TypedValue()-1);
	OnChangeAnno();
}

function NextYear()
{
	Ctrl("anno").SetTypedValue(Ctrl("anno").TypedValue()+1);
	OnChangeAnno();
}

qry:select.qry:xquery:
		for $r in sql('
	SELECT PER02_LICEN_PER.f_inicio,
	PER02_LICEN_PER.f_fin
	FROM PER02_LICEN_PER
	WHERE PER02_LICEN_PER.oi_personal_emp = {#PARAM:@id}
	AND PER02_LICEN_PER.f_inicio >= {Datetime(#PARAM:@desde)}
	AND PER02_LICEN_PER.f_fin < {Datetime(#PARAM:@hasta)}
')ROWS/ROW
